arguments.command:
python3 << 'EOF'
import json

with open('~/.openclaw/openclaw.json', 'r') as f:
    config = json.load(f)

# Set up fallbacks for each sister — different family as fallback
fallback_map = {
    'main': {
        'primary': 'openrouter/anthropic/claude-opus-4.6',
        'fallbacks': ['openrouter/google/gemini-3.1-pro-preview', 'openrouter/anthropic/claude-sonnet-4.6']
    },
    'forge': {
        'primary': 'openrouter/google/gemini-3.1-pro-preview',
        'fallbacks': ['openrouter/anthropic/claude-sonnet-4.6', 'openrouter/anthropic/claude-opus-4.6']
    },
    'scholar': {
        'primary': 'openrouter/openai/gpt-5.2',
        'fallbacks': ['openrouter/anthropic/claude-sonnet-4.6', 'openrouter/google/gemini-3.1-pro-preview']
    },
    'recovery': {
        'primary': 'openrouter/anthropic/claude-sonnet-4.6',
        'fallbacks': ['openrouter/google/gemini-3.1-pro-preview', 'openrouter/anthropic/claude-opus-4.6']
    },
    'memory': {
        'primary': 'openrouter/google/gemini-3.1-pro-preview-customtools',
        'fallbacks': ['openrouter/anthropic/claude-sonnet-4.6', 'openrouter/google/gemini-3.1-pro-preview']
    }
}

for agent in config['agents']['list']:
    aid = agent['id']
    if aid in fallback_map:
        agent['model'] = fallback_map[aid]
        print(f'✅ {aid}: primary={fallback_map[aid]["primary"]}')
        print(f'   fallbacks: {fallback_map[aid]["fallbacks"]}')

with open('~/.openclaw/openclaw.json', 'w') as f:
    json.dump(config, f, indent=4)

print('\n✅ All sisters now have fallback models!')
EOF

